INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation, order_index) VALUES
('34927863-ec9c-4a30-83db-aabb6f3186db', 'Khi ai đó hỏi ''What are you going to do this weekend?'', câu trả lời nào sau đây phù hợp nhất?', 'multiple_choice', '["I went to the cinema.","I am going to visit my grandparents.","I like playing tennis.","I was very busy."]'::jsonb, 'I am going to visit my grandparents.', 'Câu hỏi dùng ''be going to'' hỏi kế hoạch tương lai, câu trả lời cũng dùng cấu trúc tương đương.', 1),
('34927863-ec9c-4a30-83db-aabb6f3186db', 'Để rủ bạn bè đi xem phim vào cuối tuần, bạn dùng câu nào?', 'multiple_choice', '["Let''s go to the cinema on Saturday.","Did you go to the cinema?","I don''t like the cinema.","Where is the cinema?"]'::jsonb, 'Let''s go to the cinema on Saturday.', 'Cấu trúc ''Let''s + V'' dùng để đề xuất, rủ rê.', 2),
('34927863-ec9c-4a30-83db-aabb6f3186db', 'Câu nào dưới đây thể hiện một kế hoạch chắc chắn đã được lên lịch sẵn?', 'multiple_choice', '["I might stay at home.","I think it will rain.","Maybe I will read a book.","I am flying to Paris tomorrow."]'::jsonb, 'I am flying to Paris tomorrow.', 'Thì hiện tại tiếp diễn (I am flying) diễn tả kế hoạch chắc chắn trong tương lai gần.', 3),
('e98ad60a-72ba-48dc-90a1-c1edb15c417e', 'Để hỏi bạn mình đã làm gì ngày hôm qua, bạn nói thế nào?', 'multiple_choice', '["What do you do yesterday?","What did you do yesterday?","What are you doing yesterday?","What will you do yesterday?"]'::jsonb, 'What did you do yesterday?', 'Dùng trợ động từ ''did'' cho câu hỏi ở thì quá khứ đơn.', 1),
('e98ad60a-72ba-48dc-90a1-c1edb15c417e', 'Điền từ thích hợp: ''I ____ to the supermarket and bought some milk last night.''', 'multiple_choice', '["go","gone","went","going"]'::jsonb, 'went', '''Last night'' là quá khứ đơn, động từ ''go'' chuyển thành ''went''.', 2),
('e98ad60a-72ba-48dc-90a1-c1edb15c417e', 'Khi được hỏi ''Did you finish your homework last night?'', cách trả lời ngắn gọn đúng là gì?', 'multiple_choice', '["Yes, I do.","Yes, I was.","Yes, I did.","Yes, I am."]'::jsonb, 'Yes, I did.', 'Câu hỏi Yes/No bắt đầu bằng ''Did'' thì câu trả lời ngắn dùng ''did''.', 3),
('2af3a4b2-4eb7-4c64-ab5d-826b4595d59e', 'Khi muốn hỏi về ngoại hình của anh trai ai đó, bạn dùng câu nào?', 'multiple_choice', '["What does your brother like?","What does your brother look like?","How is your brother?","Who is your brother?"]'::jsonb, 'What does your brother look like?', 'Cấu trúc ''What does S look like?'' dùng để hỏi về ngoại hình.', 1),
('2af3a4b2-4eb7-4c64-ab5d-826b4595d59e', 'Điền từ: ''This sports car is very ____. It can go 200 km/h.''', 'multiple_choice', '["slow","fast","heavy","tall"]'::jsonb, 'fast', 'Tốc độ 200 km/h là rất nhanh (''fast'').', 2),
('2af3a4b2-4eb7-4c64-ab5d-826b4595d59e', 'Câu mô tả: ''She has long, curly _____.'' (Cô ấy có mái tóc dài và xoăn).', 'multiple_choice', '["eyes","nose","hair","legs"]'::jsonb, 'hair', '''Long'' và ''curly'' là tính từ miêu tả mái tóc (''hair'').', 3),
('e15a1a14-f26e-4652-858e-1a1c0f912816', 'Để từ chối lịch sự lời mời ''Would you like to come to my party?'', bạn nói gì?', 'multiple_choice', '["No, I don''t.","I hate parties.","I''d love to, but I''m busy.","Don''t invite me."]'::jsonb, 'I''d love to, but I''m busy.', '''I''d love to, but...'' là cách từ chối khéo léo.', 1),
('e15a1a14-f26e-4652-858e-1a1c0f912816', 'Bạn muốn rủ đồng nghiệp đi uống cà phê, câu nào sau đây là lời mời?', 'multiple_choice', '["Do you want to grab some coffee?","Do you like coffee?","Where is the coffee?","I am drinking coffee."]'::jsonb, 'Do you want to grab some coffee?', '''Grab some coffee'' là cách rủ rê uống cà phê thân mật.', 2),
('e15a1a14-f26e-4652-858e-1a1c0f912816', 'Đồng ý với lời đề nghị ''How about going for a walk?'', bạn đáp lại thế nào?', 'multiple_choice', '["No, thank you.","Sure, why not?","I am walking.","I don''t know you."]'::jsonb, 'Sure, why not?', '''Sure, why not?'' thể hiện sự đồng ý vui vẻ.', 3),
('7ea89040-363b-4381-8af1-7e9a9cec9b5e', 'Khi hỏi ''What''s the weather like today?'', người nói đang muốn biết điều gì?', 'multiple_choice', '["Hôm nay là thứ mấy?","Hôm nay bạn cảm thấy thế nào?","Thời tiết hôm nay thế nào?","Hôm nay bạn mặc đồ gì?"]'::jsonb, 'Thời tiết hôm nay thế nào?', '''What''s the weather like?'' là mẫu câu chuẩn hỏi thời tiết.', 1),
('7ea89040-363b-4381-8af1-7e9a9cec9b5e', 'Điền từ: ''It''s freezing outside. You should wear a ____.''', 'multiple_choice', '["T-shirt","coat","shorts","swimsuit"]'::jsonb, 'coat', 'Trời rất lạnh (''freezing'') nên cần mặc áo khoác ngoài (''coat'').', 2),
('7ea89040-363b-4381-8af1-7e9a9cec9b5e', 'Điền từ: ''We couldn''t go to the beach because it was ____.''', 'multiple_choice', '["sunny","raining","beautiful","warm"]'::jsonb, 'raining', 'Trời mưa (''raining'') là lý do khiến họ không thể đi tắm biển.', 3),
('344cd504-401e-410f-9cde-36dd57f66215', 'Bạn đến muộn và nói ''I''m so sorry for being late.'' Người kia đáp lại lịch sự thế nào?', 'multiple_choice', '["You are bad.","Go home.","That''s okay. Don''t worry.","Why are you late?"]'::jsonb, 'That''s okay. Don''t worry.', '''That''s okay. Don''t worry.'' là cách phản hồi lịch sự khi ai đó xin lỗi.', 1),
('344cd504-401e-410f-9cde-36dd57f66215', 'Phàn nàn súp bị nguội tại nhà hàng một cách lịch sự, bạn nói gì?', 'multiple_choice', '["Excuse me, but my soup is cold.","I hate this soup.","This is terrible.","Give me my money back."]'::jsonb, 'Excuse me, but my soup is cold.', 'Bắt đầu bằng ''Excuse me'' giúp câu phàn nàn lịch sự hơn.', 2),
('344cd504-401e-410f-9cde-36dd57f66215', 'Khách nói: ''My room is too noisy.'' Nhân viên khách sạn đáp lại ra sao?', 'multiple_choice', '["I don''t care.","I''m sorry, I will change your room.","It''s normal here.","Please stop talking."]'::jsonb, 'I''m sorry, I will change your room.', 'Nhân viên cần xin lỗi và đưa ra giải pháp giải quyết.', 3),
('5490e9b2-f3a1-4a92-9ed1-13dd36fb034a', 'Khi đến ngân hàng để mở tài khoản, bạn nói: ''I would like to open a bank ____.''', 'multiple_choice', '["door","account","book","money"]'::jsonb, 'account', '''Bank account'' là tài khoản ngân hàng.', 1),
('5490e9b2-f3a1-4a92-9ed1-13dd36fb034a', 'Ra bưu điện gửi hộp quà, bạn nói: ''I need to send this ____ to London.''', 'multiple_choice', '["package","letter","stamp","postcard"]'::jsonb, 'package', '''Package'' là gói bưu kiện.', 2);